// ==== click_direito.js ====
// Clique com botão direito na tabela - Menu Flutuante
(function() {
    'use strict';
    
    let currentRowData = null;
    
    function fecharMenu() {
        const menu = document.getElementById('contextMenu');
        if (menu) menu.style.display = 'none';
        
        document.querySelectorAll('.custom-table tr').forEach(tr => {
            tr.classList.remove('selecionado');
        });
        
        currentRowData = null;
    }
    
    function extrairDadosLinha(linha) {
        const colunas = linha.querySelectorAll('td');
        if (colunas.length < 2) return null;
        
        const sequencia = colunas[0]?.innerText.trim() || '';
        
        let tipoTexto = '';
        let descricao = '';
        
        for (let i = 0; i < colunas.length; i++) {
            const texto = colunas[i]?.innerText.trim() || '';
            
            if (texto.includes('📈') || texto.includes('📉') || texto.includes('Receita') || texto.includes('Despesa')) {
                tipoTexto = texto;
            }
            
            if (i > 0 && !texto.includes('R$') && !texto.includes('✅') && !texto.includes('🔴') && !texto.includes('💰') && texto.length > 5) {
                if (descricao.length < texto.length && (texto.includes('Parcela') || texto.length > 20)) {
                    descricao = texto;
                } else if (!descricao && texto.length > 10) {
                    descricao = texto;
                }
            }
        }
        
        const parcelaMatch = descricao.match(/(\d+)\/(\d+)/);
        const numeroParcela = parcelaMatch ? parcelaMatch[1] : null;
        const totalParcelas = parcelaMatch ? parcelaMatch[2] : null;
        const tipo = tipoTexto.includes('Receita') || tipoTexto.includes('📈') ? 'receita' : 'despesa';
        
        return { sequencia, descricao, numeroParcela, totalParcelas, tipo, linha };
    }
    
    function mostrarMenu(x, y, data) {
        const menu = document.getElementById('contextMenu');
        if (!menu) return;
        
        currentRowData = data;
        menu.style.left = x + 'px';
        menu.style.top = y + 'px';
        menu.style.display = 'block';
        
        setTimeout(() => {
            const rect = menu.getBoundingClientRect();
            if (rect.right > window.innerWidth) {
                menu.style.left = (window.innerWidth - rect.width - 10) + 'px';
            }
            if (rect.bottom > window.innerHeight) {
                menu.style.top = (window.innerHeight - rect.height - 10) + 'px';
            }
        }, 10);
    }
    
    function initCliqueDireito() {
        const tabela = document.querySelector('.custom-table');
        if (!tabela) return;
        
        window.addEventListener('scroll', () => fecharMenu());
        
        document.addEventListener('click', (e) => {
            if (!e.target.closest('#contextMenu')) fecharMenu();
            if (!e.target.closest('.custom-table tr')) {
                document.querySelectorAll('.custom-table tr').forEach(tr => tr.classList.remove('selecionado'));
            }
        });
        
        const menu = document.getElementById('contextMenu');
        if (menu) {
            menu.querySelectorAll('.context-menu-item').forEach(item => {
                item.addEventListener('click', (e) => {
                    e.stopPropagation();
                    const action = item.dataset.action;
                    if (currentRowData) {
                        const dados = {
                            sequencia: currentRowData.sequencia,
                            descricao: currentRowData.descricao
                        };
                        
                        if (action === 'ver_vinculos') {
                            fecharMenu();
                            const event = new CustomEvent('abrirModalVinculos', { detail: dados });
                            document.dispatchEvent(event);
                        }

                    }
                    fecharMenu();
                });
            });
        }
        
        tabela.addEventListener('contextmenu', (e) => {
            e.preventDefault();
            const linha = e.target.closest('tr');
            if (!linha || linha.querySelector('td[colspan]')) return;
            
            document.querySelectorAll('.custom-table tr').forEach(tr => tr.classList.remove('selecionado'));
            linha.classList.add('selecionado');
            
            const data = extrairDadosLinha(linha);
            if (data) mostrarMenu(e.clientX, e.clientY, data);
        });
    }
    
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initCliqueDireito);
    } else {
        initCliqueDireito();
    }
})();

// ==== vinculos.js ====
// Ver Vínculos - Toda a lógica aqui
(function() {
    'use strict';
    
    function formatarMoeda(valor) {
        return parseFloat(valor).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
    }
    
    function mostrarModalVinculos(descricao, vinculos, tipo) {
        const modal = document.getElementById('modalVinculos');
        const modalDescricao = document.getElementById('modalDescricao');
        const modalLista = document.getElementById('modalListaVinculos');
        
        if (!modal) return;
        
        modalDescricao.innerHTML = `<strong>📌 ${descricao}</strong>`;
        
        if (vinculos && vinculos.length > 0) {
            let html = '';
            vinculos.forEach(v => {
                let statusIcon = '';
                let statusClass = '';
                let statusText = '';
                
                if (v.status === 'quitado') {
                    statusIcon = '✅';
                    statusClass = 'status-quitado';
                    statusText = 'Quitado';
                } else if (v.status === 'recebido') {
                    statusIcon = '💰';
                    statusClass = 'status-recebido';
                    statusText = 'Recebido';
                } else {
                    statusIcon = '🔴';
                    statusClass = 'status-aberto';
                    statusText = 'Aberto';
                }
                
                html += `
                    <div class="item-vinculo">
                        <div style="display: flex; justify-content: space-between; align-items: center;">
                            <span class="parcela-num">📅 Parcela ${v.numero_parcela}/${v.total_parcelas}</span>
                            <span class="${statusClass}">${statusIcon} ${statusText}</span>
                        </div>
                        <span class="parcela-valor ${tipo === 'receita' ? 'receita' : 'despesa'}">
                            ${tipo === 'receita' ? '+' : '-'} R$ ${formatarMoeda(v.valor)}
                        </span>
                        <span class="parcela-data">📆 Vencimento: ${v.data_vencimento || '—'}</span>
                    </div>
                `;
            });
            modalLista.innerHTML = html;
        } else {
            modalLista.innerHTML = '<div class="sem-vinculo">ℹ️ Nenhum vínculo encontrado para esta transação.</div>';
        }
        
        modal.style.display = 'flex';
    }
    
    function fecharModal() {
        const modal = document.getElementById('modalVinculos');
        if (modal) modal.style.display = 'none';
    }
    
    function verVinculos(sequencia, descricao) {
        console.log("🔍 Buscando vínculos para sequência:", sequencia);
        
        fetch(`/api/financas/vinculos/${sequencia}`)
            .then(response => response.json())
            .then(data => {
                console.log("📦 Resposta do backend:", data);
                if (data.success) {
                    mostrarModalVinculos(data.descricao || descricao, data.vinculos || [], data.tipo);
                } else {
                    mostrarModalVinculos(descricao, [], 'despesa');
                }
            })
            .catch((error) => {
                console.error("❌ Erro:", error);
                mostrarModalVinculos(descricao, [], 'despesa');
            });
    }
    
    function init() {
        document.addEventListener('abrirModalVinculos', (e) => {
            const dados = e.detail;
            verVinculos(dados.sequencia, dados.descricao);
        });
        
        const modal = document.getElementById('modalVinculos');
        if (modal) {
            modal.querySelectorAll('.modal-vinculos-close, .btn-modal-fechar').forEach(btn => {
                btn.addEventListener('click', fecharModal);
            });
            window.addEventListener('click', (e) => {
                if (e.target === modal) fecharModal();
            });
        }
    }
    
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
})();

// ==== notificacoes_tela.js ====
if (window.Notificacao) {
    console.warn("Notificacao já existe - evitando duplicação");
} else {

    window.Notificacao = {
        
        _container: null,
        
        _criarContainer() {
            if (this._container) return this._container;
            
            this._container = document.createElement('div');
            this._container.className = 'notificacao-container';
            document.body.appendChild(this._container);
            
            return this._container;
        },
        
        _criarItem(mensagem, tipo) {
            const icones = {
                sucesso: '✅',
                erro: '❌',
                aviso: '⚠️'
            };
            
            const item = document.createElement('div');
            item.className = `notificacao-item ${tipo}`;
            item.innerHTML = `
                <span class="notificacao-icone">${icones[tipo]}</span>
                <span class="notificacao-mensagem">${mensagem}</span>
                <button class="notificacao-fechar" onclick="this.parentElement.remove()">✕</button>
            `;
            
            return item;
        },
        
        _mostrar(mensagem, tipo, duracao = 3000) {
            const container = this._criarContainer();
            const item = this._criarItem(mensagem, tipo);
            
            container.appendChild(item);
            
            if (duracao > 0) {
                setTimeout(() => {
                    item.classList.add('saindo');
                    setTimeout(() => item.remove(), 300);
                }, duracao);
            }
            
            return item;
        },
        
        sucesso(mensagem, duracao = 3000) {
            return this._mostrar(mensagem, 'sucesso', duracao);
        },
        
        erro(mensagem, duracao = 5000) {
            return this._mostrar(mensagem, 'erro', duracao);
        },
        
        aviso(mensagem, duracao = 4000) {
            return this._mostrar(mensagem, 'aviso', duracao);
        }
    };

}

// ==== click_data.js ====
// ==========================================================================
// CLICK DATA - EFEITO RIPPLE PARA BOTÕES DE FILTRO DE DATA
// ==========================================================================
// Compatível com: Finanças, Tarefas, Dashboard (todas as telas com filtro data)
// ==========================================================================

(function() {
    'use strict';
    
    function criarRipple(evento) {
        const botao = evento.currentTarget;
        
        // Remove ripple antigo se existir
        const rippleAntigo = botao.querySelector('.ripple');
        if (rippleAntigo) {
            rippleAntigo.remove();
        }
        
        // Cria o elemento da onda
        const ripple = document.createElement('span');
        ripple.classList.add('ripple');
        
        // Calcula a posição do clique
        const rect = botao.getBoundingClientRect();
        const size = Math.max(rect.width, rect.height);
        const x = evento.clientX - rect.left - size / 2;
        const y = evento.clientY - rect.top - size / 2;
        
        // Aplica estilo dinâmico
        ripple.style.width = ripple.style.height = `${size}px`;
        ripple.style.left = `${x}px`;
        ripple.style.top = `${y}px`;
        
        // Adiciona ao botão
        botao.appendChild(ripple);
        
        // Remove após animação
        ripple.addEventListener('animationend', () => {
            ripple.remove();
        });
    }
    
    function initRippleData() {
        // Seleciona botões de data em todas as telas
        const botoesData = document.querySelectorAll(
            '.btn-pure, ' +           // Botões de filtro data
            '.btn-success-pure, ' +   // Botão HOJE
            '.btn-info-pure'          // Botão I/F - MÊS
        );
        
        botoesData.forEach(botao => {
            // Garante que o botão tem position relative
            if (getComputedStyle(botao).position !== 'relative') {
                botao.style.position = 'relative';
            }
            botao.style.overflow = 'hidden';
            
            // Remove listener antigo para evitar duplicação
            botao.removeEventListener('click', criarRipple);
            botao.addEventListener('click', criarRipple);
        });
    }
    
    // Inicializa quando a página carrega
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initRippleData);
    } else {
        initRippleData();
    }
    
    // 🔥 IMPORTANTE: Reaplica após HTMX atualizar a tabela
    document.body.addEventListener('htmx:afterSwap', function(evento) {
        initRippleData();
    });
    
    document.body.addEventListener('htmx:afterSettle', function(evento) {
        initRippleData();
    });
    
    // Para telas que usam navegação tradicional (sem HTMX)
    document.body.addEventListener('turbo:load', initRippleData);
})();

// ==== btn_logout.js ====
// LOGOUT COM NOTIFICAÇÃO (sem flash)
const logoutBtn = document.getElementById('logoutBtn');

if (logoutBtn) {
    const logoutUrl = logoutBtn.dataset.logoutUrl;  // Pega a URL do data attribute
    
    logoutBtn.addEventListener('click', function(e) {
        e.preventDefault();
        
        fetch(logoutUrl, {  // <-- USA A VARIÁVEL AQUI
            method: 'POST',
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            }
        })
        .then(response => response.json())
        .then(data => {
            if (data.status === 'ok') {
                if (window.Notificacao) {
                    Notificacao.aviso(data.mensagem);
                }
                
                setTimeout(() => {
                    window.location.href = data.redirect;
                }, 1000);
            }
        })
        .catch(error => {
            console.error('Erro no logout:', error);
            window.location.href = logoutUrl;  // fallback
        });
    });
}

